  import java.util.*;
  import sailpoint.api.*;
  import sailpoint.object.*;
  import sailpoint.tools.Util;
  import java.io.BufferedReader;
  import java.io.FileNotFoundException;
  import java.io.FileReader;
  import java.io.IOException;
  import java.util.ArrayList;
  import java.util.List;

  List MAList =new ArrayList();
  String csvFileName = "\\\\ANDC1WAPP0147\\IIQDataFiles\\UpdateDescriptionOnly.csv";
  public static List readCSV() throws FileNotFoundException, IOException {
    List rows = new ArrayList();
    BufferedReader br = new BufferedReader(new FileReader(csvFileName));
    String line = "";
    String headerline = br.readLine(); 
    while((line = br.readLine()) != null) { 
      rows.add(line);
    }
    br.close(); 
    return rows;

  }
  maList = readCSV();
  int counter=0;
  String[] masterSplit=null;
  Filter filter=null;
  ManagedAttribute mgd=null;

  for(String splitStr:maList){
    masterSplit=null;
    masterSplit=splitStr.split("##");
    Map map=null;
    if(masterSplit.length==3){
      filter=null;
      mgd=null;
      filter=Filter.ignoreCase(Filter.and(Filter.eq("id",masterSplit[0]),Filter.eq("application.name",masterSplit[1])));
      mgd=context.getUniqueObject(ManagedAttribute.class,filter);
      if(mgd!=null){
       if(Util.isNotNullOrEmpty(masterSplit[2])){
          map=new HashMap();
          map.put("en_US",masterSplit[2]);
          mgd.setDescriptions(map);
        }
                                      
        /*if(Util.isNotNullOrEmpty(masterSplit[2])){
          if("true".equalsIgnoreCase(masterSplit[2])){
            mgd.setRequestable(true);
          }else{
            mgd.setRequestable(false);
          }
        }*/
        context.saveObject(mgd);
        counter++;
        if(counter%50==0){
          context.commitTransaction();
        }
      }
    }
  }
  if(counter>0){
    context.commitTransaction();
  }

  return "Success";
